function [pvtXInd,pvtYInd,rotAngl] = fImgCntAnglV03(img,angle,threshold,varargin)%% analyze image to get centroid and rotation angle% [cntX2,cntY2,rotAngl] = fImgCntAnglV02(img,threshold,vargin)% cntX, cntY: centroid [pixel]% rotAngl: rotation angle [deg]% % img: input image% threshold: threshold% vergin: if any, output figure, %       {1}: rawFrgT%       {2}: rawFrgL%% Written by Kei Nakamura% 2016/1/6 ver.1: created% 2016/1/7 ver.2: output centroid and angle% 2016/1/25 ver.3: improve%% parameters osPrp = varargin{3};rawFrgT = varargin{1};rawFrgL = varargin{2};[sizeY,sizeX] = size(img);  % image size%threC = threshold*max(max(img));    % threshold countthreC = threshold;    % threshold count%% get pivot point, thresholdimg = img.*(img>threC);   % thresholding[~,pvtXInd] = max(max(img));  % pivot x pixelpvtT = rawFrgT(pvtXInd);  % pivot time[~,pvtYInd] = min(abs(rawFrgL - 0.5*osPrp.lmb0));   % pivot y pixel%% rotation scan to seerotImg = img;   % allocationxStd = angle;   % allocationyStd = angle;   % allocationpeakP = angle;   % allocationdiffLR = angle; % allocationfor ii=1:numel(angle)    rotImg(:,:) = fImageRotV02(img,angle(ii),[pvtXInd,pvtYInd]);    [rotImg(:,:),diffLR(ii)] = fImageSymV01(rotImg,pvtXInd);   % symmetrize    rotImgX = sum(rotImg);  % x profile    rotImgY = sum(rotImg,2);  % x profile    [xStd(ii),~] = fGetRmsV01(1:sizeX,rotImgX);  % x-rms    [yStd(ii),~] = fGetRmsV01(1:sizeY,rotImgY');  % y-rms    peakP(ii) = max(rotImgX);end%% define angle based on min(diffLR)[~,rotAnglInd] = min(diffLR);   % indexrotAngl = angle(rotAnglInd);    % rotation angle [deg]a1 = tan(rotAngl*pi/180);   % y pixel/1 x pixela1C = a1 * (rawFrgL(2) - rawFrgL(1)) / (rawFrgT(2) - rawFrgT(1));   % slope in fs-nmlin1 = fPa2Line([pvtT 0.5*osPrp.lmb0],a1C); % line 1a2 = -tan((90-rotAngl)*pi/180);a2C = a2 * (rawFrgL(2) - rawFrgL(1)) / (rawFrgT(2) - rawFrgT(1));   % slope in fs-nmlin2 = fPa2Line([pvtT 0.5*osPrp.lmb0],a2C);%% figure outputif nargin>3        set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,img)    shading interp    colormap jet    hold on    plot([-200 200],[fLineX2YV01(lin1,-200) fLineX2YV01(lin1,200)],'w-')    plot([-200 200],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')    %plot([-200 200],[0.5*osPrp.lmb0,0.5*osPrp.lmb0],'w--'); % central wavelength    %plot([maxT maxT],[300 500],'w--'); % binary centroid    %plot([tOffset tOffset],[300 500],'g--'); % binary centroid    hold off    axis([-150 150 385 415])    set(gca,'fontsize',14);end%% test fig% figure(30)% subplot(1,3,1)% pcolor(rawFrgT,rawFrgL,img)% shading interp% colormap jet% hold on% plot([-200 200],[fLineX2YV01(lin1,-200) fLineX2YV01(lin1,200)],'w-')% plot([-200 200],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')% hold off% axis([-200 200 385 415])
